\begin{aligned}
                                y \amp  = 2x-3\\
                                y+3 \amp  = 2x\\
                                \frac{1}{2}y + \frac{3}{2} \amp  = x\\
                                y \amp  = \frac{1}{2}x + \frac{3}{2} \text{ (swap the variables)}\\
                            \end{aligned}

\begin{aligned}
                                y \amp  = 3-2x\\
                                y-3 \amp  = -2x\\
                                -\frac{1}{2}y + \frac{3}{2} \amp  = x\\
                                y \amp  = -\frac{1}{2}x + \frac{3}{2} \text{ (swap the variables)}\\
                            \end{aligned}

